const supabaseUrl = $env.SUPABASE_URL;
const serviceKey = $env.SUPABASE_SERVICE_ROLE_KEY;
if (!supabaseUrl || !serviceKey) throw new Error('Missing SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY in n8n');
const headers = { apikey: serviceKey, Authorization: `Bearer ${serviceKey}` };
function phtDate() { const parts = new Intl.DateTimeFormat('en-US', { timeZone: 'Asia/Manila', year: 'numeric', month: '2-digit', day: '2-digit' }).formatToParts(new Date()); const pick = (type) => parts.find((part) => part.type === type).value; return `${pick('year')}-${pick('month')}-${pick('day')}`; }
async function getJson(path) { const response = await fetch(`${supabaseUrl}/rest/v1/${path}`, { headers }); if (!response.ok) throw new Error(`Supabase GET failed ${response.status}: ${await response.text()}`); return await response.json(); }
const funds = await getJson('money_market_funds?select=id,slug,name,provider,trust_fee_pct,uitf_fund_id&is_active=eq.true&currency=eq.PHP&fund_type=eq.UITF&navpu_source=eq.uitf_com_ph');
const benchmarks = await getJson('benchmark_rates?select=rate,date&key=eq.BTR_91D&order=date.desc&limit=1');
if (!benchmarks.length) throw new Error('Missing BTR_91D benchmark. Run the BTr benchmark workflow first.');
const benchmarkRate = Number(benchmarks[0].rate);
const sourceUrl = 'https://www.uitf.com.ph/top-funds.php?class_id=4&currency=PHP&radio1=yoy';
const sourceResponse = await fetch(sourceUrl);
if (!sourceResponse.ok) throw new Error(`UITF source failed ${sourceResponse.status}`);
const html = await sourceResponse.text();
const decode = (value) => String(value || '').replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&#x27;|&#39;/g, String.fromCharCode(39)).replace(/&quot;/g, String.fromCharCode(34));
const strip = (value) => decode(value).replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
const rows = [...html.matchAll(/<tr[\s\S]*?<\/tr>/gi)].map((match) => match[0]);
const scraped = [];
for (const row of rows) { const cells = [...row.matchAll(/<td[\s\S]*?>([\s\S]*?)<\/td>/gi)].map((match) => strip(match[1])); if (cells.length < 3) continue; const hrefMatch = row.match(/fund[_-]?id=(\d+)/i); const fundId = hrefMatch ? Number(hrefMatch[1]) : null; const name = cells[0]; const navpuCell = cells.find((cell) => /^\d+(,\d{3})*(\.\d+)?$/.test(cell)); const returnCell = [...cells].reverse().find((cell) => /%/.test(cell)) || cells[cells.length - 1]; const navpu = navpuCell ? Number(navpuCell.replace(/,/g, '')) : null; const return1y = Number(String(returnCell).replace(/[^0-9.-]/g, '')); if (name && Number.isFinite(return1y)) scraped.push({ fund_id: fundId, name, navpu, return_1y: return1y }); }
if (!scraped.length) throw new Error('No UITF source rows parsed. Check uitf.com.ph table selectors.');
const allowlist = { 'chinabank cash fund': 'chinabank-cash-fund', 'chinabank money market fund': 'chinabank-money-market-fund', 'dbp unlad panimula mmf class iii': 'dbp-unlad-panimula-mmf-class-iii', 'eastwest peso money market fund': 'eastwest-peso-money-market-fund', 'landbank money market plus fund': 'landbank-money-market-plus-fund', 'manulife money market fund class a': 'manulife-money-market-fund-class-a', 'metro money market fund': 'metro-money-market-fund', 'psbank money market fund': 'psbank-money-market-fund', 'sb peso cash management fund': 'sb-peso-cash-management-fund', 'sb peso money market fund': 'sb-peso-money-market-fund' };
const norm = (value) => String(value || '').toLowerCase().replace(/&/g, 'and').replace(/[^a-z0-9]+/g, ' ').trim();
const byId = new Map(scraped.filter((row) => row.fund_id).map((row) => [String(row.fund_id), row]));
const bySlug = new Map();
for (const row of scraped) { const slug = allowlist[norm(row.name)]; if (slug) bySlug.set(slug, row); }
const today = phtDate();
const output = [];
const missing = [];
for (const fund of funds) { const scrapedRow = fund.uitf_fund_id ? byId.get(String(fund.uitf_fund_id)) : bySlug.get(fund.slug); if (!scrapedRow) { missing.push(`${fund.provider} - ${fund.name}`); continue; } const grossYield = Number(scrapedRow.return_1y) / 100; const trustFee = Number(fund.trust_fee_pct || 0); const afterTaxYield = grossYield * 0.8; const netYield = afterTaxYield - trustFee; output.push({ json: { fund_id: fund.id, date: today, navpu: scrapedRow.navpu, gross_yield_1y: Number(grossYield.toFixed(6)), after_tax_yield: Number(afterTaxYield.toFixed(6)), net_yield: Number(netYield.toFixed(6)), benchmark_rate: benchmarkRate, vs_benchmark: Number((netYield - benchmarkRate).toFixed(6)), data_source: 'scraper' } }); }
if (missing.length) throw new Error(`Missing scraped rows for ${missing.length} target funds: ${missing.join('; ')}`);
return output;
